import{_ as t,o,c as a,a2 as r}from"./chunks/framework.ac-V-Xu_.js";const m=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"en/troubleshooting.md","filePath":"en/troubleshooting.md"}'),i={name:"en/troubleshooting.md"};function n(s,e,l,d,u,c){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><p>Common issues and solutions.</p><h2 id="setup-issues" tabindex="-1">Setup Issues <a class="header-anchor" href="#setup-issues" aria-label="Permalink to &quot;Setup Issues&quot;">​</a></h2><h3 id="api-key-is-required" tabindex="-1">&quot;API key is required&quot; <a class="header-anchor" href="#api-key-is-required" aria-label="Permalink to &quot;&quot;API key is required&quot;&quot;">​</a></h3><p>Make sure you have a valid OpenRouter API key. Run <code>/setup</code> to re-enter it.</p><p>Get a key at <a href="https://openrouter.ai" target="_blank" rel="noreferrer">openrouter.ai</a>.</p><h3 id="model-not-found" tabindex="-1">&quot;Model not found&quot; <a class="header-anchor" href="#model-not-found" aria-label="Permalink to &quot;&quot;Model not found&quot;&quot;">​</a></h3><p>The model ID must match OpenRouter&#39;s format: <code>provider/model-name</code>. Use <code>/model</code> to browse available models.</p><h2 id="agent-issues" tabindex="-1">Agent Issues <a class="header-anchor" href="#agent-issues" aria-label="Permalink to &quot;Agent Issues&quot;">​</a></h2><h3 id="agent-not-appearing-in-agent-list" tabindex="-1">Agent not appearing in /agent list <a class="header-anchor" href="#agent-not-appearing-in-agent-list" aria-label="Permalink to &quot;Agent not appearing in /agent list&quot;">​</a></h3><ul><li>Check the file is in <code>.turbodev/agents/</code> (project) or <code>~/.config/turbodev/agents/</code> (global)</li><li>Ensure the filename ends with <code>.md</code></li><li>Check that <code>disable: true</code> is not set</li><li>Restart TurboDev after adding new agent files</li></ul><h3 id="custom-agent-not-overriding-built-in" tabindex="-1">Custom agent not overriding built-in <a class="header-anchor" href="#custom-agent-not-overriding-built-in" aria-label="Permalink to &quot;Custom agent not overriding built-in&quot;">​</a></h3><p>The merge is <strong>shallow</strong> — only fields you specify are overridden. Make sure the filename matches the built-in name exactly (e.g., <code>editor.md</code> to override the editor agent).</p><h3 id="permission-prompt-not-appearing" tabindex="-1">Permission prompt not appearing <a class="header-anchor" href="#permission-prompt-not-appearing" aria-label="Permalink to &quot;Permission prompt not appearing&quot;">​</a></h3><ul><li>Verify the agent has <code>permission: edit: ask</code> (not <code>allow</code>)</li><li>Check the tool is not disabled via <code>tools: edit_file: false</code> (disabled tools return an error immediately, no prompt)</li></ul><h2 id="tool-issues" tabindex="-1">Tool Issues <a class="header-anchor" href="#tool-issues" aria-label="Permalink to &quot;Tool Issues&quot;">​</a></h2><h3 id="edit-file-not-found-error" tabindex="-1">edit_file &quot;not found&quot; error <a class="header-anchor" href="#edit-file-not-found-error" aria-label="Permalink to &quot;edit_file &quot;not found&quot; error&quot;">​</a></h3><p>The <code>old_str</code> must match <strong>exactly</strong> — including whitespace and indentation. Copy the exact text from the file.</p><h3 id="bash-command-timeout" tabindex="-1">bash command timeout <a class="header-anchor" href="#bash-command-timeout" aria-label="Permalink to &quot;bash command timeout&quot;">​</a></h3><p>Increase the timeout in the command:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bash({ &quot;command&quot;: &quot;npm test&quot;, &quot;timeout&quot;: 60000 })</span></span></code></pre></div><h2 id="agents-md-issues" tabindex="-1">AGENTS.md Issues <a class="header-anchor" href="#agents-md-issues" aria-label="Permalink to &quot;AGENTS.md Issues&quot;">​</a></h2><h3 id="agents-md-not-detected-at-startup" tabindex="-1">AGENTS.md not detected at startup <a class="header-anchor" href="#agents-md-not-detected-at-startup" aria-label="Permalink to &quot;AGENTS.md not detected at startup&quot;">​</a></h3><ul><li>The file must be in the <strong>current working directory</strong> where you launched TurboDev</li><li>The filename must be exactly <code>AGENTS.md</code> (uppercase)</li><li>If you create it during a session with <code>/init</code>, it&#39;s loaded immediately</li></ul><h3 id="init-not-detecting-my-project-type" tabindex="-1">/init not detecting my project type <a class="header-anchor" href="#init-not-detecting-my-project-type" aria-label="Permalink to &quot;/init not detecting my project type&quot;">​</a></h3><p>Project detection looks for:</p><ul><li><strong>Node.js</strong>: <code>package.json</code></li><li><strong>Python</strong>: <code>pyproject.toml</code> or <code>requirements.txt</code></li><li><strong>Rust</strong>: <code>Cargo.toml</code></li><li><strong>Go</strong>: <code>go.mod</code></li></ul><h2 id="general-issues" tabindex="-1">General Issues <a class="header-anchor" href="#general-issues" aria-label="Permalink to &quot;General Issues&quot;">​</a></h2><h3 id="ai-freezes-or-takes-too-long" tabindex="-1">AI freezes or takes too long <a class="header-anchor" href="#ai-freezes-or-takes-too-long" aria-label="Permalink to &quot;AI freezes or takes too long&quot;">​</a></h3><p>Press <strong>Escape</strong> to cancel the current request. The input bar will return and you can retry or rephrase your message.</p><p>If the issue persists:</p><ul><li>The model might be generating a very long response — try a faster model</li><li>The context window might be full — use <code>/compact</code> to summarize the conversation</li><li>Check your network connection to OpenRouter</li></ul><h3 id="request-cancelled-message" tabindex="-1">Request cancelled message <a class="header-anchor" href="#request-cancelled-message" aria-label="Permalink to &quot;Request cancelled message&quot;">​</a></h3><p>If you see <code>Request cancelled. You can try sending your message again.</code> — you (or a timeout) interrupted the request. Simply resend your message.</p><h3 id="turbodev-is-slow" tabindex="-1">TurboDev is slow <a class="header-anchor" href="#turbodev-is-slow" aria-label="Permalink to &quot;TurboDev is slow&quot;">​</a></h3><ul><li>Try a faster model (e.g., <code>anthropic/claude-haiku-4-20250514</code>)</li><li>Use the plan agent for quick analysis without modifications</li><li>Reduce <code>steps</code> in agent config to limit iterations</li></ul><h3 id="blanking-or-flickering-screen" tabindex="-1">Blanking or flickering screen <a class="header-anchor" href="#blanking-or-flickering-screen" aria-label="Permalink to &quot;Blanking or flickering screen&quot;">​</a></h3><p>Make sure you&#39;re using a modern terminal emulator. Recommended:</p><ul><li><a href="https://wezterm.org" target="_blank" rel="noreferrer">WezTerm</a></li><li><a href="https://alacritty.org" target="_blank" rel="noreferrer">Alacritty</a></li><li><a href="https://sw.kovidgoyal.net/kitty/" target="_blank" rel="noreferrer">Kitty</a></li><li><a href="https://iterm2.com" target="_blank" rel="noreferrer">iTerm2</a> (macOS)</li></ul>',39)])])}const p=t(i,[["render",n]]);export{m as __pageData,p as default};
